const chatId = $('Webhook - WAHA').item.json.payload.from;
const body = $('Webhook - WAHA').item.json.payload.body;

let sessao = {};
const redisValue = $input.first() ? $input.first().json.value : null;

if (redisValue) {
  try {
    sessao = JSON.parse(redisValue);
  } catch(e) {
    sessao = {};
  }
}

if (!sessao.etapa) {
  sessao = {
    chatId: chatId,
    nome: null,
    cpf: null,
    email: null,
    cep: null,
    etapa: 'inicio',
    similares_exibidos: 0,
    similares_ids_vistos: [],
    historico: [],
    ultimo_produto_consultado: null,
    ultimo_termo_busca: null,
    opcoes_frete: [],
    frete_escolhido: null,
    pedido_id: null,
    tray_customer_id: null,
    erros_consecutivos: 0
  };
}

sessao.historico.push({ role: 'user', content: body });
if (sessao.historico.length > 20) {
  sessao.historico = sessao.historico.slice(-20);
}

return [{ json: { chatId, body, sessao } }];

const sessao = $('Code - Parsear/Criar Sessao').item.json.sessao;
const chatId = $('Code - Parsear/Criar Sessao').item.json.chatId;

sessao.etapa = 'aguardando_produto';

const mensagem = 'Ola! Bem-vindo a Papel & Cia!\n\nSou o Papeluxo, seu assistente virtual.\n\nEsta buscando uma solucao? Em que posso lhe ajudar hoje?';

return [{ json: { chatId, sessao, mensagem } }];

const sessao = $('Code - Parsear/Criar Sessao').item.json.sessao;
const chatId = $('Code - Parsear/Criar Sessao').item.json.chatId;
const body = $('Code - Parsear/Criar Sessao').item.json.body;

const prompt = 'Analise esta mensagem de cliente de papelaria: "' + body + '".

Responda APENAS com JSON valido:
{
  "intencao": "buscar_produto" | "falar_humano" | "confirmar" | "negar" | "outra",
  "termo_busca": "termo extraido ou null",
  "confianca": 0.0 a 1.0
}';

return [{ json: { prompt, chatId, sessao } }];

const geminiResponse = $input.first().json;
const sessao = $('Code - Classificar Intencao').item.json.sessao;
const chatId = $('Code - Classificar Intencao').item.json.chatId;

const texto = geminiResponse.candidates ? geminiResponse.candidates[0].content.parts[0].text : '';
const textoLimpo = texto.replace(/```json|```/g, '').trim();

let resultado;
try {
  resultado = JSON.parse(textoLimpo);
} catch(e) {
  resultado = { intencao: 'outra', termo_busca: null, confianca: 0 };
}

return [{ json: { chatId, sessao, intencao: resultado.intencao, termo_busca: resultado.termo_busca, confianca: resultado.confianca } }];

const sessao = $('Code - Parsear Classificacao').item.json.sessao;
const chatId = $('Code - Parsear Classificacao').item.json.chatId;

sessao.erros_consecutivos = (sessao.erros_consecutivos || 0) + 1;

let mensagem;
let transferir = false;

if (sessao.erros_consecutivos >= 2) {
  transferir = true;
  mensagem = null;
  sessao.etapa = 'transferindo_humano';
} else {
  mensagem = 'Foi mal, sou novo aqui na Papel & Cia... Nao consegui entender. Pode repetir?';
  sessao.etapa = 'aguardando_produto';
}

return [{ json: { chatId, sessao, mensagem, transferir } }];

const sessao = $('Code - Parsear Classificacao').item.json.sessao;
const chatId = $('Code - Parsear Classificacao').item.json.chatId;
const termo_busca = $('Code - Parsear Classificacao').item.json.termo_busca;
const response = $input.first().json;

const produtos = response.Products || response.data || [];
const primeiroProduto = (produtos[0] && produtos[0].Product) ? produtos[0].Product : (produtos[0] || null);

let mensagem;

if (primeiroProduto && primeiroProduto.id && primeiroProduto.name) {
  const preco = parseFloat(primeiroProduto.price || '0').toFixed(2).replace('.', ',');
  mensagem = 'Encontrei isso! 📦\n\n*' + primeiroProduto.name + '*\n💰 Preco: R$ ' + preco + '\n📊 Estoque: ' + (primeiroProduto.stock || '0') + ' unidades\n\nDeseja adicionar ao carrinho? (Sim/Nao)';
  sessao.etapa = 'produto_encontrado';
  sessao.ultimo_produto_consultado = primeiroProduto;
  sessao.ultimo_termo_busca = termo_busca;
  sessao.erros_consecutivos = 0;
  sessao.similares_exibidos = 0;
  sessao.similares_ids_vistos = [];
} else {
  mensagem = 'Nao encontrei "' + termo_busca + '". Tente com outro nome ou marca?';
  sessao.etapa = 'aguardando_produto';
}

return [{ json: { chatId, sessao, mensagem } }];

// Confirmar Carrinho — etapa: produto_encontrado
const sessao = $('Code - Parsear/Criar Sessao').item.json.sessao;
const chatId = $('Code - Parsear/Criar Sessao').item.json.chatId;
const body = $('Code - Parsear/Criar Sessao').item.json.body;

const prompt = 'O cliente respondeu: "' + body + '" sobre adicionar o produto ao carrinho. Classifique APENAS como JSON: {"intencao": "confirmar"|"negar"|"outra", "confianca": 0.0 a 1.0}';

return [{ json: { prompt, chatId, sessao } }];

// Parsear confirmação do Gemini
const geminiResponse = $input.first().json;
const sessao = $('Code - Confirmar Carrinho').item.json.sessao;
const chatId = $('Code - Confirmar Carrinho').item.json.chatId;

const texto = geminiResponse.candidates ? geminiResponse.candidates[0].content.parts[0].text : '';
const textoLimpo = texto.replace(/```json|```/g, '').trim();

let resultado;
try {
  resultado = JSON.parse(textoLimpo);
} catch(e) {
  resultado = { intencao: 'outra', confianca: 0 };
}

let mensagem;
if (resultado.intencao === 'negar') {
  sessao.similares_exibidos = (sessao.similares_exibidos || 0) + 1;
  if (sessao.similares_exibidos >= 5) {
    sessao.etapa = 'transferindo_humano';
    mensagem = 'Puxa, nao consegui encontrar nenhum produto que te agradasse. Vou transferir voce para um de nossos especialistas agora mesmo.';
  } else {
    mensagem = 'Entendi! Vou buscar outro produto similar para voce. Aguarde um instante...';
    sessao.etapa = 'aguardando_produto';
  }
} else {
  sessao.etapa = 'aguardando_quantidade';
  mensagem = 'Quantas unidades voce deseja? 📦';
}

return [{ json: { chatId, sessao, mensagem } }];

// Processar Quantidade — etapa: aguardando_quantidade
const sessao = $('Code - Parsear/Criar Sessao').item.json.sessao;
const chatId = $('Code - Parsear/Criar Sessao').item.json.chatId;
const body = $('Code - Parsear/Criar Sessao').item.json.body;
const match = body.match(/\d+/);
const qtd = match ? parseInt(match[0]) : 1;

const produto = sessao.ultimo_produto_consultado;
const preco = parseFloat(produto.price || '0');
const item = {
  product_id: produto.id,
  nome: produto.name,
  preco: preco,
  quantidade: qtd,
  subtotal: preco * qtd
};

const subtotalFormatado = item.subtotal.toFixed(2).replace('.', ',');
const mensagem = '✅ Adicionado ao carrinho!\n\n📦 ' + item.nome + ' × ' + qtd + ' = R$ ' + subtotalFormatado + '\n\nDeseja adicionar mais algum produto? (Sim/Nao)';

sessao.etapa = 'carrinho_ativo';

return [{ json: { chatId, sessao, mensagem, item } }];

// Mais Produtos ou Frete — etapa: carrinho_ativo
const sessao = $('Code - Parsear/Criar Sessao').item.json.sessao;
const chatId = $('Code - Parsear/Criar Sessao').item.json.chatId;
const body = $('Code - Parsear/Criar Sessao').item.json.body;

const resp = body.toLowerCase();
const sim = resp.includes('sim') || resp === 's' || resp === '1';

let mensagem;
if (sim) {
  sessao.etapa = 'aguardando_produto';
  mensagem = 'Qual outro produto voce procura?';
} else {
  sessao.etapa = 'aguardando_cep';
  mensagem = 'Para calcular o frete, preciso do seu CEP. 📦\nQual e o seu CEP?';
}

return [{ json: { chatId, sessao, mensagem } }];

// Validar CEP — etapa: aguardando_cep
const sessao = $('Code - Parsear/Criar Sessao').item.json.sessao;
const chatId = $('Code - Parsear/Criar Sessao').item.json.chatId;
const body = $('Code - Parsear/Criar Sessao').item.json.body;
const cep = body.replace(/\D/g, '');

let cepValido = cep.length === 8;
let mensagem = cepValido ? null : 'CEP invalido. Informe os 8 digitos do CEP:';

return [{ json: { chatId, sessao, cep, cepValido, mensagem } }];

// Formatar opcoes de frete
const sessao = $('Code - Validar CEP').item.json.sessao;
const chatId = $('Code - Validar CEP').item.json.chatId;
const viaCep = $('HTTP ViaCEP').item.json;
const cotacao = $input.first().json;

const cidade = viaCep.localidade || 'sua cidade';
const uf = viaCep.uf || '';
const shipping = cotacao.Quotation?.shipping || cotacao.shipping || [];

if (shipping.length === 0) {
  return [{ json: { chatId, sessao, mensagem: 'Nao encontrei opcoes de frete para este CEP. Tente outro CEP:', erroFrete: true } }];
}

const opcoes = shipping.map((s, i) => {
  const preco = parseFloat(s.price || '0').toFixed(2).replace('.', ',');
  const dias = s.deadline || '?';
  const diaTexto = dias === '1' ? 'dia util' : 'dias uteis';
  return (i+1) + '. ' + s.name + ': R$ ' + preco + ' (' + dias + ' ' + diaTexto + ')';
}).join('\n');

const mensagem = '📦 Opcoes de frete para ' + cidade + '/' + uf + ':\n\n' + opcoes + '\n\nQual opcao prefere? Digite o numero (1, 2, 3...):';

sessao.etapa = 'aguardando_frete';
sessao.opcoes_frete = shipping;
sessao.cep = $('Code - Validar CEP').item.json.cep;

return [{ json: { chatId, sessao, mensagem } }];

// Escolher Frete — etapa: aguardando_frete
const sessao = $('Code - Parsear/Criar Sessao').item.json.sessao;
const chatId = $('Code - Parsear/Criar Sessao').item.json.chatId;
const body = $('Code - Parsear/Criar Sessao').item.json.body;
const match = body.match(/\d+/);
const numero = match ? parseInt(match[0]) - 1 : 0;

const opcoes = sessao.opcoes_frete || [];
const freteEscolhido = opcoes[numero] || opcoes[0];

sessao.frete_escolhido = freteEscolhido;
sessao.etapa = 'aguardando_nome';

const precoFrete = parseFloat(freteEscolhido.price || '0').toFixed(2).replace('.', ',');
const mensagem = '✅ Frete escolhido: ' + freteEscolhido.name + ' — R$ ' + precoFrete + '\n\nAgora preciso dos seus dados para a nota fiscal.\n\nQual e o seu **nome completo**?';

return [{ json: { chatId, sessao, mensagem } }];

// Validar Nome — etapa: aguardando_nome
const sessao = $('Code - Parsear/Criar Sessao').item.json.sessao;
const chatId = $('Code - Parsear/Criar Sessao').item.json.chatId;
const nome = $('Code - Parsear/Criar Sessao').item.json.body.trim();

if (nome.length < 3) {
  sessao.etapa = 'aguardando_nome';
  return [{ json: { chatId, sessao, mensagem: 'Por favor, informe seu nome completo:' } }];
}

sessao.nome = nome;
sessao.etapa = 'aguardando_cpf';
const mensagem = 'Obrigado, ' + nome + '! 😊\n\nAgora preciso do seu CPF (apenas numeros):';

return [{ json: { chatId, sessao, mensagem } }];

// Validar CPF — etapa: aguardando_cpf
const sessao = $('Code - Parsear/Criar Sessao').item.json.sessao;
const chatId = $('Code - Parsear/Criar Sessao').item.json.chatId;
const cpf = $('Code - Parsear/Criar Sessao').item.json.body.replace(/\D/g, '');

if (cpf.length !== 11) {
  sessao.etapa = 'aguardando_cpf';
  return [{ json: { chatId, sessao, mensagem: 'CPF invalido. Informe apenas os 11 numeros:' } }];
}

sessao.cpf = cpf;
sessao.etapa = 'aguardando_email';
const mensagem = 'Perfeito! E seu e-mail para envio da nota fiscal:';

return [{ json: { chatId, sessao, mensagem } }];

// Validar Email — etapa: aguardando_email
const sessao = $('Code - Parsear/Criar Sessao').item.json.sessao;
const chatId = $('Code - Parsear/Criar Sessao').item.json.chatId;
const email = $('Code - Parsear/Criar Sessao').item.json.body.trim().toLowerCase();

if (!email.includes('@') || !email.includes('.')) {
  sessao.etapa = 'aguardando_email';
  return [{ json: { chatId, sessao, mensagem: 'E-mail invalido. Tente novamente:' } }];
}

sessao.email = email;
sessao.etapa = 'confirmando_pedido';

return [{ json: { chatId, sessao, mensagem: null } }];

// Criar Pedido — etapa: confirmando_pedido
const sessao = $('Code - Validar Email').item.json.sessao;
const chatId = $('Code - Validar Email').item.json.chatId;
const response = $input.first().json;

const clientes = response.Customers || [];
let tray_customer_id;

if (clientes.length > 0 && clientes[0].Customer) {
  tray_customer_id = clientes[0].Customer.id;
} else {
  tray_customer_id = null;
}

sessao.tray_customer_id = tray_customer_id;
sessao.etapa = 'pagamento_pendente';

return [{ json: { chatId, sessao, tray_customer_id, precisaCriarCliente: !tray_customer_id } }];

// Aguardando Pagamento — etapa: pagamento_pendente
const sessao = $('Code - Parsear/Criar Sessao').item.json.sessao;
const chatId = $('Code - Parsear/Criar Sessao').item.json.chatId;

return [{ json: { chatId, sessao, mensagem: null } }];

// Transferir para Humano
const sessao = $('Code - Parsear/Criar Sessao').item.json.sessao;
const chatId = $('Code - Parsear/Criar Sessao').item.json.chatId;

const nomeCliente = sessao.nome || '(nao informado)';

const msgCliente = '✅ *Atendente avisado!*\n\nEle ja sabe o que voce precisa.\n\n📞 *Salve este numero e me chame aqui:* (41) 99961-6806\n\nQuando chamar, diga *"Sou o ' + nomeCliente + '"* que ele ja vai saber o que voce precisa. 🚀';

return [{ json: { chatId, sessao, mensagem: msgCliente } }];
